    '["Полноценная разминка перед каждой нагрузкой","Прибавляйте мощность и вес маленькими шагами","Прислушивайтесь к плечу на следующий день после нагрузки"]',
    '["Боль при мощностных нагрузках","Ощущение нестабильности в области сочленения","Рецидив деформации ключицы — к хирургу"]',
    '[{"q":"Когда можно вернуться к контактному спорту?","a":"Только при подтверждённой полной силе и стабильности и достаточном сроке после операции, обычно около 6 месяцев. Если стояла пластина (hook plate), её сначала удаляют. Решение всегда согласуют с хирургом."},{"q":"Почему важно убрать компенсации лопатки?","a":"Перекосы и «вздёргивание» лопатки при нагрузке перегружают восстановленное сочленение и повышают риск повторной травмы. Поэтому мощность наращиваем только при чистой технике."}]'
),
(
    'shoulder_ac_repair', 5,
    'Возврат к спорту и функции',
    'От 16–24 недель (контакт — обычно около 6 месяцев)',
    '16-26',
    'Финальный этап. Плечо готовим к вашим реальным задачам: спорту, работе, нагрузкам. Возврат к контактному и силовому спорту решается индивидуально и только с разрешения хирурга — ориентир по времени около 6 месяцев. Спешка повышает риск повторной травмы и потери репозиции.',
    '["Безопасно вернуться к спорту и работе","Восстановить спортспецифические навыки","Снизить риск рецидива и повторной травмы"]',
    '["Избегайте боли и раздражения при росте нагрузок","Контактный и коллизионный спорт, тяжёлый труд над головой — только при подтверждённой полной силе и стабильности","Возврат к контакту — только по разрешению хирурга"]',
    '["Полный безболезненный активный объём движений","Контактный/коллизионный спорт и тяжёлый труд над головой — только при подтверждённой полной силе и стабильности (валидированного порога для АКС нет; ориентир по времени около 6 месяцев)","При hook plate — выполнено удаление металлоконструкции перед возвратом к контакту (решает врач очно)","Уверенно выполняете спортспецифические движения без боли и страха"]',
    'trophy', '#EC4899', '#FFF9E6',
    'Возврат к спорту и функции по силе, движению и сроку',
    '["Интеграция силы, чувства положения руки и работы всей цепи движения в упражнения вашего вида спорта","Бег, спринт, упражнения на ловкость","Защитный наплечник при необходимости","Поддерживающая домашняя программа"]',
    '["Спортивная нагрузка должна быть без боли и отёка","Боль при контакте или осевой нагрузке — стоп и к куратору"]',
    '["Возвращайтесь к нагрузке постепенно, без рывков","Сохраняйте поддерживающую программу регулярно","Прислушивайтесь к уверенности — психологическая готовность так же важна, как физическая"]',
    '["Боль или нестабильность при контакте","Рецидив деформации ключицы — к хирургу","Любой тревожный признак — обсудите с куратором или врачом"]',
    '[{"q":"Когда можно вернуться к контактному спорту?","a":"Решение индивидуально и только с разрешения хирурга — обычно при полной силе, полном объёме движений и достаточном сроке после операции (ориентир около 6 месяцев). Если стояла пластина, её сначала удаляют."},{"q":"Нужно ли продолжать упражнения после возврата к спорту?","a":"Да. Поддерживающая программа сохраняет силу плеча и снижает риск повторной проблемы и потери репозиции. Это надолго."}]'
)
ON CONFLICT (program_type, phase_number) DO NOTHING;

-- =====================================================
-- 2. Структурированные критерии перехода shoulder_ac_repair
--    (JOIN на rehab_phases по program_type+phase_number → реальный phase_id)
--    Фаза 0 (prehab) — без structured-критериев, не в WITH.
--    measurement-критериев НЕТ (в источнике числового VAS-порога нет): числа по объёму движений →
--    instructor_check (число в тексте label), качественное да/нет → self_report.
--    Фаза 5 (терминальная) несёт критерии безопасного возврата.
-- =====================================================
WITH criteria_data (
  phase_number, criterion_code, label, criterion_type,
  measurement_type, measurement_source,
  threshold_operator, threshold_value, threshold_value2,
  staleness_days, self_report_question, self_report_hint,
  position, is_required
) AS (VALUES
  -- Фаза 1 → Фаза 2 (защита и иммобилизация → восстановление подвижности)
  (1, 'passive_elevation_90_p1',  'Пассивный подъём руки не менее 90°',                                                       'instructor_check', NULL::varchar, NULL::varchar, NULL::varchar, NULL::numeric, NULL::numeric, 14::smallint, NULL::text, NULL::text, 10::smallint, TRUE),
  (1, 'passive_er_30_p1',         'Пассивный поворот руки наружу при локте у тела не менее 30°',                               'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 20::smallint, TRUE),
  (1, 'rom_tolerance_p1',         'Переносите объём движений и напряжение мышц без боли над ключицей (оценка куратора)',        'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 30::smallint, TRUE),
  (1, 'sleep_no_pain_p1',         'Можете спать без пробуждений от боли в области ключицы',                                     'self_report',      NULL, NULL, NULL, NULL, NULL, 7::smallint, 'Можете спать без пробуждений от боли в области ключицы?', 'Оцените сон за последние несколько ночей', 40::smallint, TRUE),
  (1, 'no_loss_reduction_p1',     'Нет видимой потери репозиции — деформация ключицы не возвращается (оценка куратора/врача)',   'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 50::smallint, TRUE),

  -- Фаза 2 → Фаза 3 (восстановление подвижности → восстановление силы и стабильности)
  (2, 'passive_elevation_140_p2', 'Пассивный подъём руки в плоскости лопатки не менее 140°',                                   'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 10::smallint, TRUE),
  (2, 'passive_er_60_p2',         'Пассивный поворот руки наружу при локте у тела не менее 60°',                               'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 20::smallint, TRUE),
  (2, 'active_elevation_100_p2',  'Активный подъём руки против силы тяжести не менее 100° с хорошей механикой',                 'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 30::smallint, TRUE),
  (2, 'rom_progress_painfree_p2', 'Переносите наращивание движений (от пассивных к активным) без боли (оценка куратора)',       'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 40::smallint, TRUE),
  (2, 'lift_to_shoulder_p2',      'Можете поднять руку до уровня плеча без боли и без ощущения нестабильности',                 'self_report',      NULL, NULL, NULL, NULL, NULL, 7::smallint, 'Можете поднять руку до уровня плеча без боли и без ощущения нестабильности?', 'Оцените подъём руки вперёд', 50::smallint, TRUE),

  -- Фаза 3 → Фаза 4 (восстановление силы → продвинутая сила и мощность)
  (3, 'functional_rom_p3',        'Активный и пассивный объём движений в функциональных пределах во всех направлениях (оценка куратора)', 'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 10::smallint, TRUE),
  (3, 'strength_progress_p3',     'Переносите наращивание растяжения, объёма и силовых упражнений без боли и отёка (оценка куратора)', 'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 20::smallint, TRUE),
  (3, 'no_scapular_dyskinesis_p3','Нет перекосов лопатки и компенсаций при нагрузке (оценка куратора)',                         'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 30::smallint, TRUE),
  (3, 'rotator_strength_p3',      'Сила мышц-вращателей и лопатки на хорошем уровне (валидированного АКС-порога нет, решает куратор очно)', 'instructor_check', NULL, NULL, NULL, NULL, NULL, 30::smallint, NULL, NULL, 40::smallint, FALSE),
  (3, 'exercise_painfree_p3',     'Выполняете упражнения без боли в области сочленения',                                        'self_report',      NULL, NULL, NULL, NULL, NULL, 7::smallint, 'Выполняете упражнения без боли в области акромиально-ключичного сочленения?', 'Оцените по нескольким силовым занятиям', 50::smallint, TRUE),

  -- Фаза 4 → Фаза 5 (продвинутая сила и мощность → возврат к спорту)
  (4, 'full_painfree_arom_p4',    'Полный безболезненный активный объём движений (оценка куратора)',                           'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 10::smallint, TRUE),
  (4, 'no_dyskinesis_power_p4',   'Нет перекосов и компенсаций лопатки при мощностных нагрузках (оценка куратора)',             'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 20::smallint, TRUE),
  (4, 'strength_symmetry_p4',     'Сила и симметрия относительно здоровой стороны достаточны (валидированного АКС-порога нет, решает куратор/врач очно)', 'instructor_check', NULL, NULL, NULL, NULL, NULL, 30::smallint, NULL, NULL, 30::smallint, FALSE),
  (4, 'sport_confidence_p4',      'Уверенно выполняете спортспецифические движения без боли и страха',                          'self_report',      NULL, NULL, NULL, NULL, NULL, 7::smallint, 'Уверенно выполняете движения вашего вида спорта без боли и страха?', 'Оцените по пробным спорт-специфическим движениям', 40::smallint, TRUE),
  (4, 'contact_clearance_p4',     'Для контакта/тяжёлого труда — подтверждённая полная сила и стабильность; при hook plate выполнено удаление металлоконструкции (решает врач очно)', 'instructor_check', NULL, NULL, NULL, NULL, NULL, 30::smallint, NULL, NULL, 50::smallint, FALSE),

  -- Фаза 5 (терминальная) — критерии безопасного возврата к контактному спорту/функции
  (5, 'full_painfree_arom_p5',    'Полный безболезненный активный объём движений (оценка куратора)',                           'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 10::smallint, TRUE),
  (5, 'contact_full_strength_p5', 'Контактный/коллизионный спорт и тяжёлый труд над головой — только при подтверждённой полной силе и стабильности (валидированного порога для АКС нет; ориентир по времени около 6 месяцев)', 'instructor_check', NULL, NULL, NULL, NULL, NULL, 30::smallint, NULL, NULL, 20::smallint, TRUE),
  (5, 'hook_plate_removed_p5',    'При hook plate — выполнено удаление металлоконструкции перед возвратом к контакту (решает врач очно)', 'instructor_check', NULL, NULL, NULL, NULL, NULL, 30::smallint, NULL, NULL, 30::smallint, FALSE),
  (5, 'sport_confidence_p5',      'Уверенно выполняете спортспецифические движения без боли и страха',                          'self_report',      NULL, NULL, NULL, NULL, NULL, 7::smallint, 'Уверенно выполняете движения вашего вида спорта без боли и страха?', 'Оцените по пробным спорт-специфическим движениям', 40::smallint, TRUE)
)
INSERT INTO phase_transition_criteria (
  phase_id, criterion_code, label, criterion_type,
  measurement_type, measurement_source,
  threshold_operator, threshold_value, threshold_value2, staleness_days,
  self_report_question, self_report_hint,
  position, is_required, is_active
)
SELECT
  p.id, cd.criterion_code, cd.label, cd.criterion_type,
  cd.measurement_type, cd.measurement_source,
  cd.threshold_operator, cd.threshold_value, cd.threshold_value2, cd.staleness_days,
  cd.self_report_question, cd.self_report_hint,
  cd.position, cd.is_required, TRUE
FROM criteria_data cd
JOIN rehab_phases p ON p.program_type = 'shoulder_ac_repair' AND p.phase_number = cd.phase_number
ON CONFLICT (phase_id, criterion_code) DO NOTHING;

COMMIT;
